import * as path from "node:path";

import type { ThreadsState } from "./state";

export type SessionBehaviorKind = "normal" | "orchestrator" | "subagent";

export interface SessionBehavior {
	kind: SessionBehaviorKind;
	sessionFile?: string;
	threadName?: string;
	shouldAppendOrchestratorPrompt: boolean;
	parentSessionFile?: string;
}

export interface DeriveSessionBehaviorInput {
	cwd: string;
	sessionFile?: string;
	state: ThreadsState;
}

export const BUILTIN_FILE_SHELL_TOOLS = ["read", "write", "edit", "bash", "grep", "find", "ls"] as const;

function normalizeSessionPath(sessionPath: string): string {
	return path.resolve(sessionPath);
}

function isSessionUnderDir(sessionFile: string | undefined, dir: string): boolean {
	if (!sessionFile) return false;
	const resolvedSessionFile = normalizeSessionPath(sessionFile);
	const resolvedDir = normalizeSessionPath(dir);
	const relative = path.relative(resolvedDir, resolvedSessionFile);
	return relative === "" || (!relative.startsWith("..") && !path.isAbsolute(relative));
}

function extractToolName(tool: string | { name: string }): string {
	return typeof tool === "string" ? tool : tool.name;
}

export function deriveSessionBehavior(input: DeriveSessionBehaviorInput): SessionBehavior {
	const sessionFile = input.sessionFile ? normalizeSessionPath(input.sessionFile) : undefined;
	const threadsDir = path.join(input.cwd, ".pi", "threads");
	const parentSessionFile = sessionFile ? input.state.parentBySession[sessionFile] : undefined;
	const isThreadSession = isSessionUnderDir(sessionFile, threadsDir);

	if (isThreadSession) {
		return {
			kind: "subagent",
			sessionFile,
			threadName: sessionFile ? path.basename(sessionFile, ".jsonl") : undefined,
			shouldAppendOrchestratorPrompt: false,
			parentSessionFile,
		};
	}

	if (input.state.enabled && !isThreadSession) {
		return {
			kind: "orchestrator",
			sessionFile,
			shouldAppendOrchestratorPrompt: true,
		};
	}

	return {
		kind: "normal",
		sessionFile,
		shouldAppendOrchestratorPrompt: false,
	};
}

export function resolveActiveToolsForBehavior(
	behaviorKind: SessionBehaviorKind,
	currentActiveTools: string[],
	allTools: ReadonlyArray<string | { name: string }>,
): string[] {
	const normalizedAllTools = allTools.map(extractToolName);

	if (behaviorKind !== "orchestrator") {
		const withoutDispatch = currentActiveTools.filter((toolName) => toolName !== "dispatch");
		if (withoutDispatch.length === 0 && currentActiveTools.includes("dispatch")) {
			const preferredInteractiveTools = new Set(["read", "write", "edit", "bash"]);
			return normalizedAllTools.filter(
				(toolName) =>
					preferredInteractiveTools.has(toolName) ||
					(!BUILTIN_FILE_SHELL_TOOLS.includes(toolName as (typeof BUILTIN_FILE_SHELL_TOOLS)[number]) && toolName !== "dispatch"),
			);
		}
		return withoutDispatch;
	}

	const blocked = new Set<string>(BUILTIN_FILE_SHELL_TOOLS);
	const allowed = new Set(currentActiveTools.filter((toolName) => !blocked.has(toolName)));
	if (normalizedAllTools.includes("dispatch")) {
		allowed.add("dispatch");
	}
	return normalizedAllTools.filter((toolName) => allowed.has(toolName));
}

			onTerminalInput?: (handler: (data: string) => { consume?: boolean; data?: string } | undefined) => () => void;
			theme: any;
			setStatus: (key: string, text: string | undefined) => void;
			setWidget: (key: string, content: unknown, options?: unknown) => void;
		};
	}) => {
		const { state, behavior } = resolveSessionContext(ctx);
		const currentActiveTools = pi.getActiveTools().filter((tool) => tool !== "dispatch");
		const allToolNames = pi.getAllTools().map((tool) => tool.name);

		if (!defaultActiveTools) {
			defaultActiveTools = currentActiveTools;
		}

		const strippedCachedTools = resolveActiveToolsForBehavior("orchestrator", defaultActiveTools, allToolNames)
			.filter((tool) => tool !== "dispatch");
		const isCurrentToolsetCached = arraysEqual(currentActiveTools, strippedCachedTools);
		if (!isCurrentToolsetCached) {
			defaultActiveTools = currentActiveTools;
		}

		const nextActiveTools = resolveActiveToolsForBehavior(
			behavior.kind,
			behavior.kind === "orchestrator" || isCurrentToolsetCached ? defaultActiveTools : currentActiveTools,
			allToolNames,
		);
		pi.setActiveTools(nextActiveTools);

		releaseSubagentBackListener?.();
		releaseSubagentBackListener = null;
		if (behavior.kind === "subagent" && ctx.hasUI && typeof ctx.ui.onTerminalInput === "function") {
			releaseSubagentBackListener = ctx.ui.onTerminalInput((data) => {
				if (data !== CTRL_B_INPUT) return undefined;
				return { data: "/subagents-back\n" };
			});
		}

		if (behavior.kind === "orchestrator") {
			ctx.ui.setStatus("pi-threads", ctx.ui.theme.fg("accent", "threads:on"));
		} else if (behavior.kind === "subagent") {
			ctx.ui.setStatus("pi-threads", ctx.ui.theme.fg("warning", `subagent:${behavior.threadName ?? "thread"}`));
		} else {
			ctx.ui.setStatus("pi-threads", undefined);
		}

		renderSubagentBanner(ctx, behavior);
		rebuildEpisodeCounts(ctx.sessionManager);
		return behavior;
	};

	const rememberCommandSessionSwitcher = (ctx: {
		switchSession: (sessionPath: string) => Promise<{ cancelled: boolean }>;
	}) => {
		lastCommandSwitchSession = ctx.switchSession.bind(ctx);
	};

	const switchToRememberedParent = async (ctx: {
		cwd: string;
		sessionManager: { getSessionFile(): string | undefined };
		ui: { notify: (message: string, level?: string) => void };
		switchSession?: (sessionPath: string) => Promise<{ cancelled: boolean }>;
	}) => {
		const { behavior } = resolveSessionContext(ctx);
		if (behavior.kind !== "subagent" || !behavior.parentSessionFile) {
			ctx.ui.notify("No remembered parent session for this thread.", "warning");
			return;
		}

		const switchSession = ctx.switchSession ?? lastCommandSwitchSession;
		if (!switchSession) {
			ctx.ui.notify("Ctrl+B cannot switch sessions yet in this runtime. Use /subagents-back.", "warning");
			return;
		}

		await switchSession(behavior.parentSessionFile);
	};

	// Reconstruct state on session load
	pi.on("session_start", async (_event, ctx) => {
		syncSessionMode(ctx);
	});

	pi.on("session_switch", async (_event, ctx) => {
		syncSessionMode(ctx);
	});

	// Inject orchestrator system prompt
	pi.on("before_agent_start", async (event, ctx) => {
		const { behavior } = resolveSessionContext(ctx);
		if (!behavior.shouldAppendOrchestratorPrompt) return;

		let extra = ORCHESTRATOR_PROMPT;

		// Tell the orchestrator about existing threads
		const threads = listThreads(ctx.cwd);
		if (threads.length > 0) {
			const threadInfo = threads.map((t) => {
				const count = episodeCounts.get(t) || 0;
				return `  - **${t}** (${count} episode${count !== 1 ? "s" : ""})`;
			});
			extra += `\n## Active Threads\n${threadInfo.join("\n")}\n`;
		}

		return { systemPrompt: event.systemPrompt + extra };
	});

	pi.registerCommand("threads", {
		description: "Turn thread orchestrator mode on or off for this project",
		getArgumentCompletions(prefix) {
			const values = ["on", "off"].filter((value) => value.startsWith(prefix));
			return values.length > 0 ? values.map((value) => ({ value, label: value })) : null;
		},
		handler: async (args, ctx) => {
			rememberCommandSessionSwitcher(ctx);
			const nextMode = args.trim().toLowerCase();
			if (nextMode !== "on" && nextMode !== "off") {
				const state = loadThreadsState(ctx.cwd);
				ctx.ui.notify(`Thread mode is ${state.enabled ? "on" : "off"}. Use /threads on or /threads off.`, "info");
				return;
			}

			const state = loadThreadsState(ctx.cwd);
			saveThreadsState(ctx.cwd, { ...state, enabled: nextMode === "on" });
			syncSessionMode(ctx);
			ctx.ui.notify(`Thread mode ${nextMode}.`, "info");
		},
	});

	pi.registerCommand("subagents-back", {
		description: "Return from the current subagent session to its remembered parent session",
		handler: async (_args, ctx) => {
			rememberCommandSessionSwitcher(ctx);
			await switchToRememberedParent(ctx);
		},
	});

	pi.registerShortcut("ctrl+b", {
		description: "Return to remembered parent session from a subagent",
		handler: async (ctx) => {
			await switchToRememberedParent(ctx);
		},
	});

	pi.registerCommand("subagents", {
		description: "Browse and open known subagent thread sessions",
		handler: async (_args, ctx) => {
			rememberCommandSessionSwitcher(ctx);
			if (!ctx.hasUI) {
				ctx.ui.notify("The /subagents selector requires the interactive UI.", "warning");
				return;
			}

			const { state, behavior } = resolveSessionContext(ctx);

			const parentSessionFile = behavior.parentSessionFile ?? behavior.sessionFile;
			if (!parentSessionFile) {
				ctx.ui.notify("Current session is not persisted, so parent navigation cannot be remembered.", "warning");
				return;
			}

			const parentEntries = behavior.parentSessionFile
				? loadSessionBranchFromFile(behavior.parentSessionFile)
				: ctx.sessionManager.getBranch();

			const cards = collectSubagentCards(ctx.cwd, parentEntries);
			const selected = await ctx.ui.custom<SubagentCard | undefined>(
				(_tui, theme, _keybindings, done) => new SubagentSelector(cards, theme, done),
				{
					overlay: true,
					overlayOptions: {

